from http.server import BaseHTTPRequestHandler
from openpyxl import Workbook
from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
from openpyxl.utils import get_column_letter
from openpyxl.drawing.image import Image as XLImage
import json, io, base64

LOGO_B64 = ""
SIG_B64  = ""

CO = {
    'addr' :'Zollergasse 9/26, 1070, Vienna - Austria',
    'email':'viviane.zahra@zahra-interiors.com',
    'phone':'+ 43 (0) 67682337441',
    'vat'  :'ATU77022918','eori':'ATEOS1000136890',
    'bank' :'Raiffeisen Bank / Vienna - Austria',
    'iban' :'AT47 3200 0000 1348 4274','bic':'RLNWATWW',
    'owner':'Viviane Zahra','name':'Zahra Interiors'
}

HDR_BG  = 'E8E8E8'
INK     = '2C2C2C'
MID     = '666666'
LIGHT   = '999999'
RULE    = 'CCCCCC'
STRIPE  = 'F5F5F5'
WHITE   = 'FFFFFF'
ACCENT  = '8C8C8C'
TBL_HDR = '4A4A4A'
FOOT_BG = 'EFEFEF'

def Ft(sz=9,b=False,c=INK,name='Calibri Light',italic=False):
    return Font(name=name,size=sz,bold=b,italic=italic,color=c)
def Fill(col): return PatternFill('solid',fgColor=col)
AL = Alignment(horizontal='left',  vertical='center')
AR = Alignment(horizontal='right', vertical='center')
AC = Alignment(horizontal='center',vertical='center')

def gen(data):
    wb=Workbook(); ws=wb.active
    dt =data.get('docType','Invoice'); ws.title=dt
    cur=data.get('currency','€')
    cf ='#,##0.00 "€"' if cur=='€' else '"$" #,##0.00'

    ws.page_setup.paperSize   =ws.PAPERSIZE_A4
    ws.page_setup.orientation ='portrait'
    ws.page_setup.fitToWidth  =1
    ws.page_setup.fitToHeight =1
    ws.sheet_properties.pageSetUpPr.fitToPage=True
    ws.page_margins.left  =0.5
    ws.page_margins.right =0.5
    ws.page_margins.top   =0.35
    ws.page_margins.bottom=0.35

    for i,w in enumerate([2,14,42,6,6,13,14,2]):
        ws.column_dimensions[get_column_letter(i+1)].width=w

    def W(row,col,val,font=None,fill=None,align=None,
          border=None,nf=None,mg=None,h=None):
        c=ws.cell(row=row,column=col,value=val)
        if font:   c.font      =font
        if fill:   c.fill      =fill
        if align:  c.alignment =align
        if border: c.border    =border
        if nf:     c.number_format=nf
        if mg:     ws.merge_cells(start_row=row,start_column=col,
                                  end_row=row,end_column=mg)
        if h:      ws.row_dimensions[row].height=h

    def rh(r,h): ws.row_dimensions[r].height=h

    # ── ROW 1: top margin ─────────────────────────────────────────────────────
    rh(1,6)

    # ── ROWS 2-5: HEADER BAND — light gray ────────────────────────────────────
    for r in range(2,6):
        for c in range(1,9): W(r,c,None,fill=Fill(HDR_BG))
    rh(2,8); rh(3,28); rh(4,6); rh(5,4)

    # Logo — transparent PNG blends perfectly on gray
    try:
        logo_xl=XLImage(io.BytesIO(base64.b64decode(LOGO_B64)))
        logo_xl.width=220; logo_xl.height=16
        ws.add_image(logo_xl,'B3')
    except Exception: pass

    # QUOTATION title right
    W(3,5,dt.upper(),Ft(14,True,INK,'Calibri Light'),
      fill=Fill(HDR_BG),align=AR,mg=7)
    for c in [1,2,3,4,8]: W(3,c,None,fill=Fill(HDR_BG))

    # ── ROW 6: thin accent rule ────────────────────────────────────────────────
    for c in range(1,9):
        ws.cell(row=6,column=c).border=Border(
            bottom=Side(style='thin',color=ACCENT))
    rh(6,3)

    # ── ROW 7: spacer ─────────────────────────────────────────────────────────
    rh(7,10)

    # ── DOC INFO (right cols F-G) + CLIENT block (left cols B-E) ─────────────
    r=8
    info=[]
    info.append(('Quotation No.' if dt=='Quotation' else 'Invoice No.',
                  data.get('docNumber','')))
    info.append(('Date',data.get('date','')))
    if data.get('clientVat'): info.append(('Client VAT',data['clientVat']))
    info.append(('Our VAT',CO['vat']))
    info.append(('EORI',CO['eori']))
    if data.get('workStart'): info.append(('Work Start',data['workStart']))
    if data.get('workEnd'):   info.append(('Work End',  data['workEnd']))

    for i,(lbl,val) in enumerate(info):
        rr=r+i
        W(rr,6,lbl,Ft(8,False,LIGHT),align=AR)
        W(rr,7,val,Ft(9,True,INK),   align=AL)
        rh(rr,14)

    # "Client:" label
    W(r,2,'Client:',Ft(8,False,LIGHT),align=AL,h=14)
    # Client name — large, bold
    W(r+1,2,data.get('clientName',''),
      Ft(12,True,INK,'Calibri'),align=AL,mg=5,h=20)
    # Client address lines
    addr=[l for l in(data.get('clientAddress','')or'').replace('\n','\n').split('\n')if l.strip()]
    for i,line in enumerate(addr):
        rr=r+2+i
        W(rr,2,line,Ft(9,False,MID),align=AL,mg=5,h=13)

    client_end=r+2+len(addr)
    info_end  =r+len(info)
    r=max(client_end,info_end)+1
    rh(r,6); r+=1

    # ── PROJECT BAND ──────────────────────────────────────────────────────────
    for c in range(1,9): W(r,c,None,fill=Fill(STRIPE))
    # "Project:" label small, then project name bold
    W(r,2,'Project:',Ft(8,False,LIGHT),fill=Fill(STRIPE),align=AL,h=14)
    # second row for project name
    r+=1
    for c in range(1,9): W(r,c,None,fill=Fill(STRIPE))
    W(r,2,data.get('projectName',''),
      Ft(10,True,INK),fill=Fill(STRIPE),align=AL,mg=4,h=20)
    loc=data.get('location','')
    if loc:
        W(r,5,'Location:  '+loc,Ft(9,False,MID),fill=Fill(STRIPE),align=AL,mg=7)
    r+=1; rh(r,8); r+=1

    # ── LINE ITEMS ────────────────────────────────────────────────────────────
    items=data.get('items',[])
    scope=[l for l in(data.get('scopeLines')or[])if isinstance(l,str)]

    if items and len(items)>0:
        th_fill=Fill(TBL_HDR); th_font=Ft(8,True,WHITE,'Calibri')
        for c in [1,8]: W(r,c,None,fill=th_fill)
        W(r,2,'ITEM',       th_font,th_fill,AC,h=20)
        W(r,3,'DESCRIPTION',th_font,th_fill,AL)
        W(r,4,'QTY',        th_font,th_fill,AC)
        W(r,5,None,         fill=th_fill)
        W(r,6,'UNIT PRICE', th_font,th_fill,AR)
        W(r,7,'TOTAL',      th_font,th_fill,AR)
        r+=1

        for idx,item in enumerate(items):
            rf=Fill(STRIPE) if idx%2==0 else Fill(WHITE)
            W(r,1,None,fill=rf); W(r,8,None,fill=rf)
            W(r,2,item.get('itemNumber',''),Ft(9,False,MID),rf,AC,h=20)
            dc=ws.cell(row=r,column=3,value=item.get('description',''))
            dc.font     =Ft(9,False,INK)
            dc.fill     =rf
            dc.alignment=Alignment(horizontal='left',vertical='center',wrap_text=True)
            W(r,4,item.get('qty',0),  Ft(9,False,INK),rf,AC)
            W(r,5,None,fill=rf)
            W(r,6,item.get('price',0),Ft(9,False,INK),rf,AR,nf=cf)
            tv=(item.get('qty',0)or 0)*(item.get('price',0)or 0)
            W(r,7,tv,Ft(9,True,INK),rf,AR,nf=cf)
            rh(r,20); r+=1

        # thin rule after table
        for c in range(2,8):
            ws.cell(row=r,column=c).border=Border(top=Side(style='thin',color=RULE))
        rh(r,4); r+=1

    # ── TOTALS ────────────────────────────────────────────────────────────────
    # Auto-compute subtotal from line items; fall back to manual entry if no items
    if items and len(items)>0:
        te=sum((i.get('qty',0)or 0)*(i.get('price',0)or 0) for i in items)
    else:
        te=data.get('totalExclVat',0)or 0
    vp=data.get('vatPercent',0)or 0
    va=te*vp/100; gr=te+va

    rh(r,6); r+=1
    W(r,6,'Subtotal excl. VAT',Ft(9,False,MID),align=AR)
    W(r,7,te,Ft(9,False,INK),align=AR,nf=cf,h=16); r+=1

    if vp>0:
        W(r,6,f'VAT ({vp}%)',Ft(9,False,MID),align=AR)
        W(r,7,va,Ft(9,False,INK),align=AR,nf=cf,h=16); r+=1
    else:
        W(r,6,'VAT',Ft(9,False,MID),align=AR)
        W(r,7,'Reverse Charge',Ft(8,False,LIGHT),align=AR,h=16); r+=1

    # accent rule
    for c in range(6,8):
        ws.cell(row=r,column=c).border=Border(top=Side(style='thin',color=ACCENT))
    rh(r,3); r+=1

    # Total row — light gray band
    for c in range(1,9): W(r,c,None,fill=Fill(HDR_BG))
    W(r,6,'TOTAL '+cur,Ft(11,True,INK),fill=Fill(HDR_BG),align=AR)
    W(r,7,gr,Ft(12,True,INK),fill=Fill(HDR_BG),align=AR,nf=cf,h=26)
    r+=1; rh(r,12); r+=1

    # ── ADDITIONAL NOTES ──────────────────────────────────────────────────────
    if scope and len(scope)>0:
        W(r,2,'ADDITIONAL NOTES',Ft(8,True,ACCENT,'Calibri'),align=AL,h=18)
        for c in range(2,8):
            ws.cell(row=r,column=c).border=Border(
                bottom=Side(style='thin',color=ACCENT))
        r+=1; rh(r,4); r+=1
        for line in scope:
            is_phase=line.strip().lower().startswith('phase')or line.strip().startswith('##')
            cl=line.replace('##','').strip()
            if is_phase:
                rh(r,5); r+=1
                W(r,2,cl,Ft(9,True,INK),align=AL,mg=7,h=16)
            elif cl:
                W(r,2,cl,Ft(9,False,MID),align=AL,mg=7,h=14)
            r+=1
        rh(r,8); r+=1

    # ── PAYMENT TERMS ─────────────────────────────────────────────────────────
    pt=data.get('paymentTerms',[])
    if pt and len(pt)>0:
        W(r,2,'PAYMENT TERMS',Ft(8,True,ACCENT,'Calibri'),align=AL,h=18)
        for c in range(2,8):
            ws.cell(row=r,column=c).border=Border(
                bottom=Side(style='thin',color=ACCENT))
        r+=1; rh(r,4); r+=1
        for t in pt:
            if isinstance(t,str)and t.strip():
                W(r,2,t.strip(),Ft(9,False,MID),align=AL,mg=7,h=14); r+=1
        rh(r,8); r+=1

    # ── SIGNATURE BLOCK ───────────────────────────────────────────────────────
    rh(r,8); r+=1
    for c in range(1,9):
        ws.cell(row=r,column=c).border=Border(top=Side(style='thin',color=RULE))
    rh(r,3); r+=1

    sig_label_row=r
    W(r,2,'Authorised Signature',Ft(7,False,LIGHT,italic=True),align=AL,h=12)
    W(r,5,'Client Acceptance',   Ft(7,False,LIGHT,italic=True),align=AL,mg=7)
    r+=1

    try:
        sig_img=XLImage(io.BytesIO(base64.b64decode(SIG_B64)))
        sig_img.height=44
        sig_img.width =int(264*(44/251))
        ws.add_image(sig_img,f'B{sig_label_row-3}')
    except Exception: pass

    rh(r,4); r+=1
    for c in range(2,5):
        ws.cell(row=r,column=c).border=Border(bottom=Side(style='thin',color=RULE))
    for c in range(5,8):
        ws.cell(row=r,column=c).border=Border(bottom=Side(style='thin',color=RULE))
    rh(r,20); r+=1
    W(r,2,CO['owner'],Ft(9,True,INK), align=AL,h=14)
    W(r,5,'_________________________',Ft(9,False,LIGHT),align=AL,mg=7)
    r+=1
    W(r,2,CO['name'], Ft(8,False,MID),align=AL,h=12)
    r+=1; rh(r,14); r+=1   # generous spacer before footer

    # ── FOOTER — light gray, text lifted with proper padding ─────────────────
    footer_start=r
    # 6 rows: top-pad, 4 content rows, bottom-pad
    for rr in range(r,r+6):
        for c in range(1,9): W(rr,c,None,fill=Fill(FOOT_BG))
    rh(footer_start,  8)   # top padding — lifted from edge
    rh(footer_start+1,12)
    rh(footer_start+2,12)
    rh(footer_start+3,12)
    rh(footer_start+4,12)
    rh(footer_start+5,8)   # bottom padding — text doesn't touch base

    ff=Ft(7.5,False,LIGHT)
    fa=Alignment(horizontal='center',vertical='center')
    fl=[
        CO['addr'],
        f"{CO['email']}  ·  {CO['phone']}",
        f"VAT {CO['vat']}  ·  EORI {CO['eori']}",
        f"{CO['bank']}  ·  IBAN {CO['iban']}  ·  BIC {CO['bic']}"
    ]
    for i,line in enumerate(fl):
        rr=footer_start+1+i
        W(rr,1,line,ff,fill=Fill(FOOT_BG),align=fa,mg=8)

    ws.print_area=f'A1:H{footer_start+6}'

    buf=io.BytesIO(); wb.save(buf); buf.seek(0)
    return buf.getvalue()

class handler(BaseHTTPRequestHandler):
    def do_POST(self):
        body=self.rfile.read(int(self.headers.get('Content-Length',0)))
        data=json.loads(body)
        xls=gen(data)
        fn=data.get('docNumber','doc')+'.xlsx'
        self.send_response(200)
        self.send_header('Content-Type','application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')
        self.send_header('Content-Disposition',f'attachment; filename="{fn}"')
        self.send_header('Access-Control-Allow-Origin','*')
        self.send_header('Access-Control-Allow-Methods','POST, OPTIONS')
        self.send_header('Access-Control-Allow-Headers','Content-Type')
        self.end_headers()
        self.wfile.write(xls)
    def do_OPTIONS(self):
        self.send_response(200)
        self.send_header('Access-Control-Allow-Origin','*')
        self.send_header('Access-Control-Allow-Methods','POST, OPTIONS')
        self.send_header('Access-Control-Allow-Headers','Content-Type')
        self.end_headers()
